import React, { useState } from "react";
import "../App.css";
import { Container, Form, Button, Spinner } from "react-bootstrap";
import axios from "axios";

const HomePage = () => {
  const [title, setTitle] = useState("");
  const [papers, setPapers] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const handleSearch = async (e) => {
    e.preventDefault();
    setLoading(true);
    setPapers([]);
    setError("");

    try {
      const response = await axios.post("http://localhost:4000/search_papers/", {
        title: title,
      });

      setPapers(response.data.papers || []);
    } catch (err) {
      console.error(err);
      setError("Failed to fetch papers. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="mx-4 my-4">
      <Container align="center">
        <h3>Find Research Papers using arXiv API</h3>

        <Form onSubmit={handleSearch} className="my-4" style={{ maxWidth: 500 }}>
          <Form.Control
            type="text"
            placeholder="Enter paper title or topic"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
          />
          <Button variant="primary" type="submit" className="mt-2" disabled={loading}>
            {loading ? <Spinner animation="border" size="sm" /> : "Search Papers"}
          </Button>
        </Form>

        {error && <p className="text-danger">{error}</p>}

        {papers.length > 0 && (
          <div className="mt-4 text-start" style={{ maxWidth: 600 }}>
            <h5>Results:</h5>
            <ul>
              {papers.map((paper, idx) => (
                <li key={idx}>
                  <strong>{paper.title}</strong><br />
                  <a href={paper.link} target="_blank" rel="noopener noreferrer">
                    Download PDF
                  </a>
                </li>
              ))}
            </ul>
          </div>
        )}
      </Container>
    </div>
  );
};

export default HomePage;
